<template><div><h2>❤️ 我的收藏</h2><div v-if="favs.length" class="product-grid"><router-link v-for="p in favs" :key="p.id" :to="'/products/'+p.id" class="prod-card"><div class="prod-img"><span class="prod-emoji">🎁</span></div><div class="prod-info"><div class="prod-name">{{ p.name }}</div><div class="price">¥{{ p.price }}</div></div></router-link></div><div v-else class="empty">还没有收藏任何商品</div></div></template>
<script setup>import { ref, onMounted } from 'vue'; import request from '@/utils/request'; const favs = ref([]); onMounted(async () => { try { favs.value = await request.get('/products/my-favorites') } catch {} });</script>
<style scoped>.product-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}.prod-card{background:#fff;border-radius:14px;overflow:hidden;text-decoration:none;border:1px solid #F0F0F0}.prod-img{height:120px;display:flex;align-items:center;justify-content:center;background:#F8F9FA}.prod-emoji{font-size:40px}.prod-info{padding:12px}.prod-name{font-size:13px;margin-bottom:4px;color:#2D3436}.price{font-size:16px;font-weight:700;color:#FF6B35}.empty{text-align:center;padding:60px;color:#B2BEC3}</style>
